import Sidebar from "./Sidebar";

const Layout = ({ children }: any) => {
  return (
    <div style={{ display: "flex" }}>
      <Sidebar />

      <div style={{ width: "100%" }}>
        
        <div
          style={{
            background: "white",
            padding: "15px 30px",
            borderBottom: "1px solid #eee",
            fontWeight: "500"
          }}
        >
          Unified Resource Management System
        </div>

        <div className="page-container">{children}</div>

      </div>
    </div>
  );
};

export default Layout;
